args.css:
@keyframes slideIn { from { transform: translateY(20px); opacity: 0;
          } to { transform: translateY(0); opacity: 1;
          }
      }
.container { 
  padding: 30px; 
  background: linear-gradient(135deg, #1e1e1e, #2a2a2a); 
  height: 100vh; 
  display: flex; 
  flex-direction: column; 
  animation: slideIn 0.4s ease-out;
  border: 1px solid #444;
  border-radius: 12px;
      }
.header { font-size: 28px; font-weight: 800; margin-bottom: 10px; background: linear-gradient(90deg, #ff8a00, #e52e71); -webkit-background-clip: text; -webkit-text-fill-color: transparent;
      }
.desc { font-size: 14px; color: #aaa; margin-bottom: 30px; line-height: 1.5;
      }
.form-group { margin-bottom: 20px;
      }
.label { display: block; font-size: 12px; font-weight: 600; color: #888; margin-bottom: 6px; text-transform: uppercase; letter-spacing: 1px;
      }
.input { 
  width: 100%; 
  padding: 12px; 
  background: rgba(0,
          0,
          0,
          0.3); 
  border: 1px solid #444; 
  border-radius: 8px; 
  color: white; 
  font-size: 16px; 
  transition: all 0.2s;
      }
.input:focus { border-color: #e52e71; outline: none; background: rgba(0,
          0,
          0,
          0.5);
      }
.btn { 
  margin-top: auto; 
  padding: 14px; 
  background: linear-gradient(90deg, #ff8a00, #e52e71); 
  color: white; 
  border: none; 
  border-radius: 8px; 
  font-size: 16px; 
  font-weight: 600; 
  cursor: pointer; 
  transition: transform 0.1s;
      }
.btn:active { transform: scale(0.98);
      }
